import { __ } from "@wordpress/i18n";
import {
	AlignmentControl,
	BlockControls,
	InspectorControls,
	useBlockProps,
	useSettings,
} from "@wordpress/block-editor";
import {
	__experimentalNumberControl,
	__experimentalUnitControl,
	BaseControl,
	ColorPalette,
	PanelBody,
	TextControl,
} from "@wordpress/components";
import "./editor.scss";
import { useEffect, useRef, useState } from "@wordpress/element";

const toNumberAttribute = (value) => {
	if (value === "" || value === undefined) {
		return undefined;
	}

	return Number(value);
};

export default function Edit({ attributes, setAttributes }) {
	const [colors] = useSettings("color.palette");
	const [count, setCount] = useState(0);
	const blockRef = useRef(null);
	const blockProps = useBlockProps({
		ref: blockRef,
		className: `has-text-align-${attributes.alignment}`,
		style: {
			"--number-size": attributes.numberSize,
			"--number-color": attributes.numberColor,
			"--text-size": attributes.textSize,
			"--text-color": attributes.textColor,
			"--text-gap": attributes.textGap,
		},
	});

	useEffect(() => {
		const element = blockRef.current;
		let animationFrame;

		if (!element) {
			return;
		}

		function startAnimation() {
			const start = 0;
			const startTime = performance.now();
			const duration = Number(attributes.duration);
			const endNumber = Number(attributes.endNumber);

			setCount(start);

			if (!duration || duration <= 0) {
				setCount(endNumber);
				return;
			}

			function animate(time) {
				const progress = Math.min((time - startTime) / duration, 1);
				const value = Math.floor(start + (endNumber - start) * progress);

				setCount(value);

				if (progress < 1) {
					animationFrame = requestAnimationFrame(animate);
				}
			}

			animationFrame = requestAnimationFrame(animate);
		}

		const observer = new IntersectionObserver(([entry]) => {
			if (entry.isIntersecting) {
				startAnimation();
				observer.disconnect();
			}
		});

		observer.observe(element);

		return () => {
			observer.disconnect();
			cancelAnimationFrame(animationFrame);
		};
	}, [attributes.endNumber, attributes.duration]);

	return (
		<>
			<BlockControls>
				<AlignmentControl
					value={attributes.alignment}
					onChange={(value) => setAttributes({ alignment: value })}
				/>
			</BlockControls>

			<InspectorControls>
				<PanelBody title="Settings">
					<TextControl
						label="Prefix"
						value={attributes.prefix || ""}
						onChange={(value) => setAttributes({ prefix: value })}
					/>
					<__experimentalNumberControl
						label="End Number"
						value={attributes.endNumber}
						onChange={(value) =>
							setAttributes({
								endNumber: toNumberAttribute(value),
							})
						}
					/>
					<TextControl
						label="Suffix"
						value={attributes.suffix || ""}
						onChange={(value) => setAttributes({ suffix: value })}
					/>
					<__experimentalNumberControl
						label="Duration (in ms)"
						value={attributes.duration || ""}
						onChange={(value) =>
							setAttributes({
								duration: toNumberAttribute(value),
							})
						}
					/>
					<BaseControl label="Number Size">
						<__experimentalUnitControl
							value={attributes.numberSize}
							onChange={(value) => setAttributes({ numberSize: value })}
						/>
					</BaseControl>
					<BaseControl label="Number Color">
						<ColorPalette
							colors={colors}
							value={attributes.numberColor}
							onChange={(color) => setAttributes({ numberColor: color })}
						/>
					</BaseControl>
					<TextControl
						label="Text"
						value={attributes.text || ""}
						onChange={(value) => setAttributes({ text: value })}
					/>
					<BaseControl label="Text Size">
						<__experimentalUnitControl
							value={attributes.textSize}
							onChange={(value) => setAttributes({ textSize: value })}
						/>
					</BaseControl>
					<BaseControl label="Text Color">
						<ColorPalette
							colors={colors}
							value={attributes.textColor}
							onChange={(color) => setAttributes({ textColor: color })}
						/>
					</BaseControl>
					<BaseControl label="Text Gap">
						<__experimentalUnitControl
							value={attributes.textGap}
							onChange={(value) => setAttributes({ textGap: value })}
						/>
					</BaseControl>
				</PanelBody>
			</InspectorControls>

			<div {...blockProps}>
				<p className="number-counter">
					{" "}
					{attributes.prefix}
					{count}
					{attributes.suffix}
				</p>
				<p className="number-counter__text"> {attributes.text} </p>
			</div>
		</>
	);
}
