import { useBlockProps } from "@wordpress/block-editor";

export default function save({ attributes }) {
	const blockProps = useBlockProps.save({
		className: `has-text-align-${attributes.alignment}`,
		style: {
			"--number-size": attributes.numberSize,
			"--number-color": attributes.numberColor,
			"--text-size": attributes.textSize,
			"--text-color": attributes.textColor,
			"--text-gap": attributes.textGap,
		},
	});

	return (
		<div {...blockProps}>
			<span className="number-counter">{attributes.prefix}</span>
			<span
				className="number-counter number-counter__number"
				data-start="0"
				data-end={attributes.endNumber}
				data-duration={attributes.duration}
			>
				{0}
			</span>
			<span className="number-counter">{attributes.suffix}</span>
			<p className="number-counter__text"> {attributes.text} </p>
		</div>
	);
}
